head.script:
//-------------------------------------------------------------------------
// 전역변수
//-------------------------------------------------------------------------
scwin.loUpperLobranCd = $c.data.getMemInfo("loUpperLobranCd"); // 물류 상위 점소 코드
scwin.userClsCd = $c.data.getMemInfo("userClsCd"); // 사용자구분코드 (02:협력업체(운송))
scwin.status = "H";
scwin.strCurDate = WebSquare.date.getCurrentServerDate();  // 서버를 기준으로 현재 날짜 반환
scwin.strPreDate = scwin.strCurDate.substring(0, 6) + "01";  // 조회시작일자(현재 날짜가 포함된 달의 시작 일자)

scwin.btnFlag = "";  // 신규, 수정 구분자
scwin.rowFlag = "";  // 등록, 수정 후 저장 안하고 다른 master row 선택 불가능 구분자	
scwin.pos_groupCode = 0;  // 저장전 DataSet의 RowPosition을 저장 변수 
scwin._lobranCd = "";
scwin.breakFlag = "N"; //validation check
scwin.oilPusanJ = "N"; //6AA(부산지사)이면서 자사중기 등록여부

scwin.olddata = "";
scwin.eventCnt = 0;
scwin.cvsslMgntNoValue = "";

scwin.eqCd = "";
scwin.eqShortCd = "";
scwin.hveqKndCd = "";
scwin.hveqKndNm = "";
scwin.hveqNrmCd = "";
scwin.hveqNrmNm = "";
//-------------------------------------------------------------------------
// 화면로딩시
//-------------------------------------------------------------------------
scwin.onpageload = function() {

    //점소
    $c.sbm.execute(sbm_lobran);
    // 그리드 주유소 column
    $c.sbm.execute(sbm_oilStatCd);
    // 필요장비 규격코드
    $c.sbm.execute(sbm_nesEqNrmCdCopy);
    $c.sbm.execute(sbm_nesEqNrmCd);

    // $c.gus.cfDisableObjects(udc_grid2_down);
    udc_grid2_down.setDisabled(true);
    btn_Save.setDisabled(true);

    scwin.f_OnWrkIndictClsCdChanged();    

    const codeOptions = [
        { grpCd: "SD060", compID: "gr_wrkIndictNoList:impExpClsCd, gr_heavyEquipWorkResults:impExpClsCd" }, // 셀렉트
        { grpCd: "OP182", compID: "gr_heavyEquipWorkResults:pchsAdjmStdCd" }, // 셀렉트
        { grpCd: "OP002", compID: "gr_heavyEquipWorkResults:pchsAdptMintCnt" }, // 셀렉트
        { grpCd: "OP911", compID: "gr_heavyEquipWorkResults:pchsAdptShiftCnt" }, // 셀렉트
        { grpCd: "OP270", compID: "gr_heavyEquipWorkResults:ctrlPchsPcostRsn" }, // 셀렉트
        { grpCd: "OP199", compID: "gr_heavyEquipWorkResults:tformWrkImpleKndCd" }, // 셀렉트
    ];
    $c.data.setCommonCode(codeOptions);	

};





//-------------------------------------------------------------------------
// UDC 기본값 세팅
//-------------------------------------------------------------------------
scwin.onUdcCompleted = function() {
};

scwin.ondataload = function() {
    udc_ica_date.setInitDate(scwin.strPreDate, scwin.strCurDate);
    acb_lobranCd.setValue(scwin.loUpperLobranCd);
    ed_works_01.focus()


}


//-------------------------------------------------------------------------
//  콤보세팅 (작업실적 신규/수정시 콤보세팅) / 작업단계
//-------------------------------------------------------------------------
scwin.f_OnWrkIndictClsCdChanged = function() {

	for(i = 0 ; i < ds_heavyEquipWorkResults.getTotalRow(); i ++) {

		let wrkIndictClsCd = ds_heavyEquipWorkResults.getCellData(i, "wrkIndictClsCd");
		let impExpClsCd    = ds_heavyEquipWorkResults.getCellData(i, "impExpClsCd");
		let indictNo	   = ds_heavyEquipWorkResults.getCellData(i, "wrkIndictNo");
		let indictNoIdx    = "";

		//작업단계콤보 세팅
		if (wrkIndictClsCd == "P") {

			indictNoIdx = ds_heavyEquipWorkResults.getCellData("wrkIndictNo", indictNo);
            dma_wrkStpCd.set("upperWrkStpCd", "01");
            dma_wrkStpCd.set("lvl", "03");
            dma_wrkStpCd.set("wrkPlanTrgtYn", "1");
            $c.sbm.execute(sbm_wrkStpCd)

		} 

		if ( wrkIndictClsCd == "C" || wrkIndictClsCd == "Y" || wrkIndictClsCd == "T" ) {
			//C : 수출입X, 작업단계 : 장치, 보관이적,포장
            dma_wrkStpCd.set("upperWrkStpCd", "03");
            dma_wrkStpCd.set("lvl", "03");
            dma_wrkStpCd.set("wrkPlanTrgtYn", "1");
            $c.sbm.execute(sbm_wrkStpCd)
		}
	}
}


//-------------------------------------------------------------------------
// 조회조건에 맞는 지시번호 조회 / f_qeryList
//-------------------------------------------------------------------------
scwin.btn_retrieve_onClick = function (e) {

	if (!$c.gus.cfValidate([ica_fromDt, ica_toDt])) {	// 필수조건 : 조회일자
  		return;
	}

    if(!$c.gus.cfIsAfterDate(ica_fromDt.getValue(), ica_toDt.getValue())) {
        $c.win.alert(MSG_CM_ERR_039);
        ica_fromDt.focus();
        return;
    }


    let wrkPlCd 	= ed_works_01.getValue();
    let cvsslMgntNo = ed_cvsslMgntNo.getValue();

    dma_condition.set("fromDt", ica_fromDt.getValue());			// 조회시작일자(필수조건 : XXXXXXXX)
    dma_condition.set("toDt", ica_toDt.getValue());				// 조회종료일자(필수조건 : XXXXXXXX)
    dma_condition.set("wrkDt", "");						// 작업일자
    dma_condition.set("lobranCd", acb_lobranCd.getValue());	// 점소코드
    dma_condition.set("wrkPlCd", wrkPlCd);					// 작업장코드
    dma_condition.set("cvsslMgntNo", cvsslMgntNo);				// 본선관리번호
    dma_condition.set("eqCd", "");						// 
    dma_condition.set("wrkIndictClsCd", "");						// 작업지시구분명
    dma_condition.set("wrkIndictNo", "");						// 하역지시번호
    dma_condition.set("dptWrkPlCd", wrkPlCd);					// 작업장코드


    if(wrkPlCd == "" && cvsslMgntNo =="") {

    	$c.win.alert("본선관리번호 또는 작업장코드를 입력하세요"); 
    	ed_cvsslMgntNo.focus();
        return;
    } 

    ds_wrkIndictNoList.removeAll();
    ds_heavyEquipWorkResults.removeAll();

    //지시번호 조회
    $c.sbm.execute(sbm_searchHeavyEquipWorkIndictNoList);

};

//-------------------------------------------------------------------------
// 작업시간 입력시 유효성체크
//-------------------------------------------------------------------------
scwin.f_validateWrkTime = function(row) {

	let wrkDt    = ds_heavyEquipWorkResults.getCellData(row,"wrkDt");
	let wrkStDt  = ds_heavyEquipWorkResults.getCellData(row,"wrkStDt");
	let wrkStHh  = ds_heavyEquipWorkResults.getCellData(row,"wrkStHh");
	let wrkEndDt = ds_heavyEquipWorkResults.getCellData(row,"wrkEndDt");
	let wrkEndHh = ds_heavyEquipWorkResults.getCellData(row,"wrkEndHh");

	// let wrkDtAfterDt = wrkDt.toDate("YYYYMMDD").after(0, 0, 1).format("YYYYMMDD");
	let wrkDtAfterDt = $c.date.addDate(wrkDt, 1);

	if (ds_heavyEquipWorkResults.getCellData(row,"shiftClsCd") == 'D') {

		if (ds_heavyEquipWorkResults.getCellData(row,"wrkStDt").length > 0 && ds_heavyEquipWorkResults.getCellData(row,"wrkStDt") != ds_heavyEquipWorkResults.getCellData(row,"wrkDt")) {
			$c.win.alert($c.data.getMessage(MSG_CM_ERR_030,"작업일자와 같은날만 가능합니다", ["주간의 작업시작일자"]));
			ds_wrkIndictNoList.setRowPosition(row); 
			gr_wrkIndictNoList.setFocusedCell(row, "wrkStDt");
			return false;
		}

	} else {

		if (ds_heavyEquipWorkResults.getCellData(row,"wrkStDt").length > 0 
				&& (ds_heavyEquipWorkResults.getCellData(row,"wrkStDt") < ds_heavyEquipWorkResults.getCellData(row,"wrkDt") || ds_heavyEquipWorkResults.getCellData(row,"wrkStDt") > wrkDtAfterDt)) {
			$c.win.alert($c.data.getMessage(MSG_CM_ERR_030 , "작업일자 하루이후까지만 가능합니다", ["야간/심야의 작업시작일자"]));
			return false;
		}

		if (ds_heavyEquipWorkResults.getCellData(row,"wrkEndDt") == wrkDtAfterDt) {

			if (ds_heavyEquipWorkResults.getCellData(row,"wrkEndHh") > '0800') {
				$c.win.alert("야간/심야의 작업종료시간은 08시 이전이어야 합니다.");
	      		return;
			}
		}
	}

	if (ds_heavyEquipWorkResults.getCellData(row,"wrkStDt").length == 0 || ds_heavyEquipWorkResults.getCellData(row,"wrkEndDt").length == 0) return true;
	if (ds_heavyEquipWorkResults.getCellData(row,"wrkStDt").length != 8 || ds_heavyEquipWorkResults.getCellData(row,"wrkEndDt").length != 8 || !$c.gus.cfIsAfterDate(ds_heavyEquipWorkResults.getCellData(row,"wrkStDt"), ds_heavyEquipWorkResults.getCellData(row,"wrkEndDt"), false)) {
		$c.win.alert(MSG_CM_ERR_039); // 시작일자를 종료일 이전으로 선택[입력]하여 주십시오.
		return false;
	}

	if (ds_heavyEquipWorkResults.getCellData(row,"wrkStHh").length == 0)
		return true;
	if (ds_heavyEquipWorkResults.getCellData(row,"wrkStHh").length != 4) {
		$c.win.alert($c.data.getMessage(MSG_CM_ERR_055, ["시간형식"]));
	    return false;
	}

	if (ds_heavyEquipWorkResults.getCellData(row,"wrkEndDt").length > 0 && (ds_heavyEquipWorkResults.getCellData(row,"wrkEndDt") < ds_heavyEquipWorkResults.getCellData(row,"wrkDt") || ds_heavyEquipWorkResults.getCellData(row,"wrkEndDt") > wrkDtAfterDt)) {
        $c.win.alert($c.data.getMessage(MSG_CM_ERR_030, "작업일자 하루이후까지만 가능합니다", ["종료일자"]));
		return false;
	}
	if (ds_heavyEquipWorkResults.getCellData(row,"wrkStDt").length == 0 || ds_heavyEquipWorkResults.getCellData(row,"wrkEndDt").length == 0)
		return true;

	if (ds_heavyEquipWorkResults.getCellData(row,"wrkStDt").length != 8 || ds_heavyEquipWorkResults.getCellData(row,"wrkEndDt").length != 8 || !$c.gus.cfIsAfterDate(ds_heavyEquipWorkResults.getCellData(row,"wrkStDt"), ds_heavyEquipWorkResults.getCellData(row,"wrkEndDt"), false)) {
	    $c.win.alert(MSG_CM_ERR_039); // 시작일자를 종료일 이전으로 선택[입력]하여 주십시오.
	    return false;
	}
	if (ds_heavyEquipWorkResults.getCellData(row,"wrkEndHh").length == 0)
		return true;
	if (ds_heavyEquipWorkResults.getCellData(row,"wrkEndHh").length != 4) {
		$c.win.alert($c.data.getMessage(MSG_CM_ERR_055, ["시간형식"]));
	    return false;
	}

	if (ds_heavyEquipWorkResults.getCellData(row,"wrkStHh").substring(0,2) > "23") {
		$c.win.alert($c.data.getMessage(MSG_CM_ERR_021,["작업시간"])); // "@은(는) 시가 잘못되었습니다."
		return;
	}
	if (ds_heavyEquipWorkResults.getCellData(row,"wrkStHh").substring(2,4) > "59") {
		$c.win.alert($c.data.getMessage(MSG_CM_ERR_022,["작업시간"])); // "@은(는) 분이 잘못되었습니다."
		return;
	}

	if (ds_heavyEquipWorkResults.getCellData(row,"wrkEndHh").substring(0,2) > "24") {
		$c.win.alert($c.data.getMessage(MSG_CM_ERR_022,["작업시간"])); // "@은(는) 시가 잘못되었습니다."
		return;
	}
	if (ds_heavyEquipWorkResults.getCellData(row,"wrkEndHh").substring(0,2) == "00" && ds_heavyEquipWorkResults.getCellData(row,"wrkEndHh").substring(2,2) == "00") {
		$c.win.alert($c.data.getMessage(MSG_CM_ERR_022,["작업시간"])); // "@은(는) 분이 잘못되었습니다."
		return;
	}
	if (ds_heavyEquipWorkResults.getCellData(row,"wrkEndHh").substring(0,2) == "24" && ds_heavyEquipWorkResults.getCellData(row,"wrkEndHh").substring(2,2) > "00") {
		$c.win.alert($c.data.getMessage(MSG_CM_ERR_022,["작업시간"])); // "@은(는) 분이 잘못되었습니다."
		return;
	}
	if (ds_heavyEquipWorkResults.getCellData(row,"wrkEndHh").substring(2,4) > "59") {
		$c.win.alert($c.data.getMessage(MSG_CM_ERR_022,["작업시간"])); // "@은(는) 분이 잘못되었습니다."
		return;
	}

	if (ds_heavyEquipWorkResults.getCellData(row,"wrkStDt") == ds_heavyEquipWorkResults.getCellData(row,"wrkEndDt")) {
		if (ds_heavyEquipWorkResults.getCellData(row,"wrkStHh") >= ds_heavyEquipWorkResults.getCellData(row,"wrkEndHh")) {
   			$c.win.alert("시작시간을 종료시간보다 작게 입력하여 주십시오.");
			return false;
		}
	}
	return true;

}

//-------------------------------------------------------------------------
//작업시간계산 (작업실적그리드)
//-------------------------------------------------------------------------
scwin.f_CalcWrkTimeWorkResult = function(row) {

	let indictNoCnt = "";
	let wrkStDt		= "";
	let wrkStHh		= "";
	let wrkEndDt	= "";
	let wrkEndHh	= "";
	let mealFlag	= 0;
	let wrkDtAfterDt = "";

	wrkStDt = ds_heavyEquipWorkResults.getCellData(row,"wrkStDt");
	wrkStHh = ds_heavyEquipWorkResults.getCellData(row,"wrkStHh");
	wrkEndDt = ds_heavyEquipWorkResults.getCellData(row,"wrkEndDt");
	wrkEndHh = ds_heavyEquipWorkResults.getCellData(row,"wrkEndHh");
	mealYn	 = ds_heavyEquipWorkResults.getCellData(row,"mealYn");

    if (wrkStDt.length != 8) {
        return;
    }

	if (wrkStHh.length != 4) {
        return;
    }
	if (wrkEndDt.length != 8) {
        return;
    }

	if (wrkEndHh.length != 4) {
        return;
    }



    if(!$c.date.isDate(wrkStDt)){
        $c.win.alert("시작일자는 'YYYYMMDD' 형식이어야 합니다.");
        return;
    }

    if(!$c.date.isDate(wrkEndDt)){
        $c.win.alert("시작일자는 'YYYYMMDD' 형식이어야 합니다.");
        return;
    }




    if (!$c.gus.cfIsAfterDate(wrkStDt, wrkEndDt, false)) {
	    return;

	//작업지시번호 시작일자 종료일자 체크 
	} else if (wrkStDt == wrkEndDt && wrkStHh > wrkEndHh) {

		//시작일자 종료일자 체크
		wrkEndDt = wrkEndDt.toDate("YYYYMMDD").after(0, 0, 1).format("YYYYMMDD");

        if (wrkStDt == wrkEndDt && wrkStHh > wrkEndHh) {
		    return;
		}
	}


	let v_daysBetween = $c.date.diffDate(wrkStDt, wrkEndDt);
	let v_diff 		= 0;	//총시간차이
	let v_diffHh 	= 0;	//시간차이
	let v_diffMm 	= 0;	//분차이
	let v_StHh 		= 0;	//시작시간
	let v_StMm 		= 0;	//시작분
	let v_EndHh 	= 0;	//종료시간
	let v_EndMm 	= 0;	//종료분

    v_StHh =  Number(wrkStHh.substring(0,2));
    v_StMm = Number(wrkStHh.substring(2,4));

    v_EndHh = Number(wrkEndHh.substring(0,2));
    v_EndMm = Number(wrkEndHh.substring(2,4));


	if ( Number(v_daysBetween) > 0 ) {
		v_daysBetween = Number(v_daysBetween) - 1;

		// 날짜차이*24시간*60분 + (24시간*60분 - 시작시간*60분 + 시작분수) + (종료시간*60분 + 종료분수)
		v_diff = Number(v_daysBetween) * 24 * 60 
				+ (24 * 60 - Number(v_StHh) * 60 - Number(v_StMm)) 
				+ (Number(v_EndHh) * 60 + Number(v_EndMm));
	} else {
		// 종료시간 - 시작시간
		v_diff = (Number(v_EndHh) * 60 + Number(v_EndMm)) - (Number(v_StHh) * 60 + Number(v_StMm));
	}

	v_diffHh = Math.floor(Number(Number(v_diff) / 60));
	v_diffMm = Number(Number(v_diff) % 60);

	ds_heavyEquipWorkResults.setCellData(row,"totInputHhCnt", v_diffHh);
	ds_heavyEquipWorkResults.setCellData(row,"totInputMintCnt", v_diffMm);

	if(mealYn != 0) {
        v_diffHh = Number(v_diffHh - (mealYn));
    }

	ds_heavyEquipWorkResults.setCellData(row,"realOprtHhCnt", v_diffHh);
	ds_heavyEquipWorkResults.setCellData(row,"realOprtMintCnt", v_diffMm);

	ds_heavyEquipWorkResults.setCellData(row,"pchsAdptHhCnt", ds_heavyEquipWorkResults.getCellData(row,"realOprtHhCnt"));
	ds_heavyEquipWorkResults.setCellData(row,"pchsAdptMintCnt", ds_heavyEquipWorkResults.getCellData(row,"realOprtMintCnt"));
    gr_heavyEquipWorkResults.refreshRow(row);

} 

//-------------------------------------------------------------------------
//작업시간계산 - 실적그리드 입력 중 수정하게 될 시 타게되는 func
//-------------------------------------------------------------------------
scwin.f_CalcWrkTimeEdit = function(row) {
	let wrkStDt		= "";
	let wrkStHh		= "";
	let wrkEndDt	= "";
	let wrkEndHh	= "";
	let mealFlag	= 0;

	wrkStDt  = ds_wrkIndictNoList.getCellData(row,"wrkStDt");
	wrkStHh  = ds_wrkIndictNoList.getCellData(row,"wrkStHh");
	wrkEndDt = ds_wrkIndictNoList.getCellData(row,"wrkEndDt");
	wrkEndHh = ds_wrkIndictNoList.getCellData(row,"wrkEndHh");
	mealYn	 = ds_wrkIndictNoList.getCellData(row,"mealYn");

	if (wrkStDt.length != 8) return;
	if (wrkStHh.length != 4) return;
	if (wrkEndDt.length != 8) return;
	if (wrkEndHh.length != 4) return;

	if (!$c.gus.cfIsAfterDate(wrkStDt, wrkEndDt, false)) return;	
	if (wrkStDt == wrkEndDt && wrkStHh > wrkEndHh) return;

	let v_daysBetween = $c.date.diffDate(wrkStDt, wrkEndDt);
	let v_diff 		= 0;	//총시간차이
	let v_diffHh 	= 0;	//시간차이
	let v_diffMm 	= 0;	//분차이
	let v_StHh 		= 0;	//시작시간
	let v_StMm 		= 0;	//시작분
	let v_EndHh 	= 0;	//종료시간
	let v_EndMm 	= 0;	//종료분

	if (Number( wrkStHh.substring(0,2) ) < "10") {
		v_StHh = Number( wrkStHh.substring(1,1) );
		v_StMm = Number( wrkStHh.substring(2,2) );
	} else {
		v_StHh = Number( wrkStHh.substring(0,2) );
		v_StMm = Number( wrkStHh.substring(2,2) );
	}

	if (Number( wrkEndHh.substring(0,2) ) < "10") {
		v_EndHh = Number( wrkEndHh.substring(1,1) );
		v_EndMm = Number( wrkEndHh.substring(2,2) );
	} else {
		v_EndHh = Number( wrkEndHh.substring(0,2) );
		v_EndMm = Number( wrkEndHh.substring(2,2) );
	}

	if ( Number(v_daysBetween) > 0 ) {

		v_daysBetween = Number(v_daysBetween) - 1;

		// 날짜차이*24시간*60분 + (24시간*60분 - 시작시간*60분 + 시작분수) + (종료시간*60분 + 종료분수)
		v_diff = Number(v_daysBetween) * 24 * 60 
				+ (24 * 60 - Number(v_StHh) * 60 - Number(v_StMm)) 
				+ (Number(v_EndHh) * 60 + Number(v_EndMm));
	} else {

		// 종료시간 - 시작시간
		v_diff = (Number(v_EndHh) * 60 + Number(v_EndMm)) - (Number(v_StHh) * 60 + Number(v_StMm));
	}

	v_diffHh = Number(Number(v_diff) / 60);
	v_diffMm = Number(Number(v_diff) % 60);

	ds_wrkIndictNoList.setCellData(row,"totInputHhCnt", v_diffHh);
	ds_wrkIndictNoList.setCellData(row,"totInputMintCnt", v_diffMm);

	//mealYn = 0 or 1
	if(mealYn != 0) v_diffHh = v_diffHh - (mealYn);

	ds_wrkIndictNoList.setCellData(row,"realOprtHhCnt", v_diffHh);
	ds_wrkIndictNoList.setCellData(row,"realOprtMintCnt", v_diffMm);
	ds_wrkIndictNoList.modifyAllStatus("R");


}


