scwin.f_CalcPchsPcost = async function(row) {

	// 필수 입력 체크
	let eqCd			 = ds_heavyEquipWorkResults.getCellData(row, "eqCd");
	let wrkDt			 = ds_heavyEquipWorkResults.getCellData(row, "wrkDt");
	let pchsAdjmStdCd    = ds_heavyEquipWorkResults.getCellData(row, "pchsAdjmStdCd");
	let pchsAdptHhCnt    = ds_heavyEquipWorkResults.getCellData(row, "pchsAdptHhCnt");
	let pchsAdptMintCnt  = ds_heavyEquipWorkResults.getCellData(row, "pchsAdptMintCnt");
	let upr   			 = ds_heavyEquipWorkResults.getCellData(row, "upr");
	let wrkWt		     = ds_heavyEquipWorkResults.getCellData(row, "wrkWt");
	let pchsAdptShiftCnt = ds_heavyEquipWorkResults.getCellData(row, "pchsAdptShiftCnt");
	let copCoClntNo		 = ds_heavyEquipWorkResults.getCellData(row, "copCoClntNo");
	let nesEqNrmCd		 = ds_heavyEquipWorkResults.getCellData(row, "nesEqNrmCd");
	let nesEqNrmNm		 = ds_heavyEquipWorkResults.getCellData(row, "nesEqNrmNm");
	let shiftClsCd		 = ds_heavyEquipWorkResults.getCellData(row, "shiftClsCd");
	let posnClsCd		 = ds_heavyEquipWorkResults.getCellData(row, "posnClsCd"); 

  	// 하불임계산기준 = 시간당
	if (pchsAdjmStdCd == "H"){			
	  	if (! await $c.gus.isNum(pchsAdptHhCnt)){
            return;
        } 

        if (pchsAdptHhCnt == "" && pchsAdptMintCnt == "" ) {
            await $c.win.alert("하불임 적용시간을 입력하시오.");
            ds_heavyEquipWorkResults.setCellData(row, "pchsPcostChk", "F");
            return;
        } else {
        	gr_heavyEquipWorkResults.setHeaderColor("column166", "black");
        	gr_heavyEquipWorkResults.setHeaderColor("column169", "black");
        	gr_heavyEquipWorkResults.setHeaderColor("column175", "red");
        	gr_heavyEquipWorkResults.setHeaderColor("column172", "red");
        }

		if (pchsAdptHhCnt == 0 && pchsAdptMintCnt == 0 ) {
			await $c.win.alert("하불임 적용시간을 입력하시오.");
	  		return;
		}
	//톤당	
	} else if ("T" == pchsAdjmStdCd) {	
		if (wrkWt < 1) {
			await $c.win.alert("작업톤수를 입력하시오.");
	  		return;
		} else {
            gr_heavyEquipWorkResults.setHeaderColor("column166", "red");
        	gr_heavyEquipWorkResults.setHeaderColor("column169", "black");
        	gr_heavyEquipWorkResults.setHeaderColor("column175", "black");
        	gr_heavyEquipWorkResults.setHeaderColor("column172", "black");

		  	//하불임적용기준 톤일경우 순가동시간을 매입시간으로 넣어준다.
			ds_heavyEquipWorkResults.setCellData(row, "pchsAdptHhCnt", ds_heavyEquipWorkResults.getCellData(row, "realOprtHhCnt"));
			ds_heavyEquipWorkResults.setCellData(row, "pchsAdptMintCnt", ds_heavyEquipWorkResults.getCellData(row, "realOprtMintCnt"));
		}
	// 쉬프트당	
	} else if (pchsAdjmStdCd == "S") {
		if (pchsAdptShiftCnt == "" ) {
			$c.win.alert("하불임 적용쉬프트를 입력하시오.");
	  		return;
		} else {
        	gr_heavyEquipWorkResults.setHeaderColor("column169", "red");
        	gr_heavyEquipWorkResults.setHeaderColor("column175", "black");
        	gr_heavyEquipWorkResults.setHeaderColor("column172", "black");
            gr_heavyEquipWorkResults.setHeaderColor("column166", "black");

			//하불임적용기준 쉬프트일경우 순가동시간을 매입시간으로 넣어준다.
			ds_heavyEquipWorkResults.setCellData(row, "pchsAdptHhCnt", ds_heavyEquipWorkResults.getCellData(row, "realOprtHhCnt"));
			ds_heavyEquipWorkResults.setCellData(row, "pchsAdptMintCnt", ds_heavyEquipWorkResults.getCellData(row, "realOprtMintCnt"));
		}




    let index = "";
    for(i=0 ; i < ds_trffCls.getTotalRow() ; i++)	{
        if(pchsAdptShiftCnt == ds_trffCls.getCellData(i, "cd") )	{
                index = i;
                break;	
            }
		}
	} else if ("" == pchsAdjmStdCd) {
		await $c.win.alert("하불임계산기준을 입력하시오.");
		return;
	}

	if (ds_heavyEquipBasisInformation.getTotalRow() == 0) {
		await $c.win.alert($c.data.getMessage(MSG_CM_WRN_008, ["중기정보"]));
		return;
	}

	let v_eqNrmCd = ds_heavyEquipWorkResults.getCellData(row, "hveqNrmCd");
	let v_clntNo = ds_heavyEquipWorkResults.getCellData(row, "copCoClntNo"); //협력업체

	// 자사면 공통요율 사용
	if (ds_heavyEquipWorkResults.getCellData(row, "posnClsCd") == 'J') {
		v_clntNo = " ";
	} else {
		// if (! await $c.gus.cfValidate([copCoClntNo])) {
		// 	//자사가 아닌경우 협력업체코드가 없으면 리턴
		// 	return;
		// }
	}
	// 조회 조건 DataSet에 입력
	dma_searchPchsPcost.set("lobranCd", acb_lobranCd.getValue());
	dma_searchPchsPcost.set("clntNo", v_clntNo);
	dma_searchPchsPcost.set("eqKndCd", ds_heavyEquipWorkResults.getCellData(row, "hveqKndCd"));

	//필요규격이 있으면 중기규격대신 필요규격사용
	if ( ds_heavyEquipWorkResults.getCellData(row,"nesEqNrmCd") != "") {

		dma_searchPchsPcost.set("eqNrmCd", ds_heavyEquipWorkResults.getCellData(row,"nesEqNrmCd"));

	} else {
		dma_searchPchsPcost.set("eqNrmCd", v_eqNrmCd);
	}

	dma_searchPchsPcost.set("wrkUnitCd",  ds_heavyEquipWorkResults.getCellData(row,"pchsAdjmStdCd"));
	dma_searchPchsPcost.set("stDt",  ds_heavyEquipWorkResults.getCellData(row,"wrkStDt"));

	// 조회 조건1 DataSet에 입력
// 	if (ds_searchPchsPcost1.CountRow == 0) {
		//[2022.04.28 수정] 헤더값이 고정이 됨에 따라 처음 중기실적이 없는 경우데 행추가로 생성된 dma_searchPchsPcost1 이 
		//이후 실적이 존재하는 데이터에 대해 매입원가 계산버튼을 누르면 값이 잘못매핑되어 계산이 잘못되어짐 (적용시간이 거래처코드값으로 매핑되어 계산됨)
		// $c.gus.cfCopyDataSetHeader(ds_heavyEquipWorkResults, ds_searchPchsPcost1); tocWrkPlYn
// 	}

	// let v_data_str = ds_heavyEquipWorkResults.ExportData(ds_heavyEquipWorkResults.RowPosition, ds_heavyEquipWorkResults.RowPosition, false); 
    let v_data_str = ds_heavyEquipWorkResults.getRowData(ds_heavyEquipWorkResults.getRowPosition());    

	ds_searchPchsPcost1.setData(v_data_str) 
    $c.sbm.execute(sbm_searchPchsPcost);
}


