scwin.f_wrkStepChk = function(i) {
	let wrkPlCd 	= ed_works_01.getValue();
    let cvsslMgntNo = ed_cvsslMgntNo.getValue();
  	let wrkIndictClsCd = "";
  	let wrkIndictClsNm = "";
  	let impExpClsCd	   = "";
  	let wrkStpCd 	   = "";
  	let eqCd		   = "";

  	wrkIndictClsCd  = ds_heavyEquipWorkResults.getCellData(i,"wrkIndictClsCd");
	wrkIndictClsNm  = ds_heavyEquipWorkResults.getCellData(i,"wrkIndictClsNm");
	impExpClsCd 	= ds_heavyEquipWorkResults.getCellData(i,"impExpClsCd");
	wrkStpCd 		= ds_heavyEquipWorkResults.getCellData(i,"wrkStpCd");
	wrkDt 			= ds_heavyEquipWorkResults.getCellData(i,"wrkDt");
	wrkIndictNo		= ds_heavyEquipWorkResults.getCellData(i,"wrkIndictNo");
	pchsDeptCd		= ds_heavyEquipWorkResults.getCellData(i,"pchsDeptCd");
	pchsPcost		= ds_heavyEquipWorkResults.getCellData(i,"pchsPcost");
	eqShortCd		= ds_heavyEquipWorkResults.getCellData(i,"eqShortCd");
	oilStatCd		= ds_heavyEquipWorkResults.getCellData(i,"oilStatCd");
	oilStatNm		= ds_heavyEquipWorkResults.getCellData(i,"oilStatNm");
	oilingVol		= ds_heavyEquipWorkResults.getCellData(i,"oilingVol");

	if(wrkIndictClsCd == ""){

		scwin.breakFlag = "Y";
		$c.win.alert((i+1) + "행의 하역구분을 선택하세요.");
		return;

	} else if($c.gus.cfIsNull(wrkStpCd)){ 

		$c.win.alert((i+1)+"번째 작업실적  데이터의 작업단계는 필수입력항목 입니다.");
		scwin.breakFlag = "Y";
		if(ds_heavyEquipWorkResults.getRowStatus(i) == "C" && i != 1) {
            // ds_heavyEquipWorkResults.undoRow(i);
            ds_heavyEquipWorkResults.removeRow(ds_heavyEquipWorkResults.getTotalRow()-1);


		} 
        return;

	}else if ($c.gus.cfIsNull(eqShortCd)) { 

		//중기단축코드
		$c.win.alert((i+1)+"번째 작업실적 데이터의 중기는 필수입력항목 입니다.");
		scwin.breakFlag = "Y";
		if(ds_heavyEquipWorkResults.getRowStatus(i) == "C" && i != 1) {
            // ds_heavyEquipWorkResults.undoRow(i);
            ds_heavyEquipWorkResults.removeRow(ds_heavyEquipWorkResults.getTotalRow()-1);
        } 
		//ds_heavyEquipWorkResults.undo();
		return;

	} else if ($c.gus.cfIsNull(impExpClsCd)) {

		$c.win.alert((i+1)+"번째 작업실적 수출입구분은 필수입력항목 입니다.");
		scwin.breakFlag = "Y";
		if(ds_heavyEquipWorkResults.getRowStatus(i) == "C" && i != 1) {
            // ds_heavyEquipWorkResults.undoRow(i);
            ds_heavyEquipWorkResults.removeRow(ds_heavyEquipWorkResults.getTotalRow()-1);
        }

		return;

	} else if (pchsPcost == 0 || $c.gus.cfIsNull(pchsPcost)){

		$c.win.alert((i+1)+"번째 작업실적 매입원가는 필수항목 입니다.");
		scwin.breakFlag = "Y";
		if(ds_heavyEquipWorkResults.getRowStatus(i) == "C" && i != 1) {
            // ds_heavyEquipWorkResults.undoRow(i);
            ds_heavyEquipWorkResults.removeRow(ds_heavyEquipWorkResults.getTotalRow()-1);
        }

		return;

	} else if (ds_heavyEquipWorkResults.getCellData(i,"wrkStDt").trim() == "") {

		$c.win.alert((i+1)+"번째 작업실적  데이터의 작업시작일자는 필수입력항목 입니다.");
		scwin.breakFlag = "Y";
		if(ds_heavyEquipWorkResults.getRowStatus(i) == "C" && i != 1) {
            // ds_heavyEquipWorkResults.undoRow(i);
            ds_heavyEquipWorkResults.removeRow(ds_heavyEquipWorkResults.getTotalRow()-1);
        }

        gr_heavyEquipWorkResults.setFocusedCell(i, "wrkStDt");
		return;

	} else if (ds_heavyEquipWorkResults.getCellData(i,"wrkStHh").trim() == "") {

		$c.win.alert((i+1)+"번째 작업실적  데이터의 작업시작시간는 필수입력항목 입니다.");
		scwin.breakFlag = "Y";
		if(ds_heavyEquipWorkResults.getRowStatus(i) == "C" && i != 1) {
            // ds_heavyEquipWorkResults.undoRow(i);
            ds_heavyEquipWorkResults.removeRow(ds_heavyEquipWorkResults.getTotalRow()-1);
        }

		return;        

	} else if (ds_heavyEquipWorkResults.getCellData(i,"wrkEndDt").trim() == "") {

		$c.win.alert((i+1)+"번째 작업실적  데이터의 작업종료일자는 필수입력항목 입니다.");
		scwin.breakFlag = "Y";
		if(ds_heavyEquipWorkResults.getRowStatus(i) == "C" && i != 1) {
            // ds_heavyEquipWorkResults.undoRow(i);
            ds_heavyEquipWorkResults.removeRow(ds_heavyEquipWorkResults.getTotalRow()-1);
        }
        gr_heavyEquipWorkResults.setFocusedCell(i, "wrkEndDt");
		return;

	} else if (ds_heavyEquipWorkResults.getCellData(i,"wrkEndHh").trim() == "") {

		scwin.breakFlag = "Y";
		$c.win.alert((i+1)+"번째 작업실적  데이터의 작업종료시간는 필수입력항목 입니다.");
		if(ds_heavyEquipWorkResults.getRowStatus(i) == "C" && i != 1) {
            // ds_heavyEquipWorkResults.undoRow(i);
            ds_heavyEquipWorkResults.removeRow(ds_heavyEquipWorkResults.getTotalRow()-1);
        } 
		return;

	} else if ($c.gus.cfIsNull(pchsDeptCd)) {

		$c.win.alert((i+1)+"번째 작업실적  데이터의 매입부서는 필수입력항목 입니다.");
		scwin.breakFlag = "Y";
		if(ds_heavyEquipWorkResults.getRowStatus(i) == "C" && i != 1) {
            // ds_heavyEquipWorkResults.undoRow(i);
            ds_heavyEquipWorkResults.removeRow(ds_heavyEquipWorkResults.getTotalRow()-1);
        } 

		return;

	} else if(scwin.oilPusanJ == "N" && scwin.oilingVol == 0 && scwin.oilStatCd != "") {

		$c.win.alert((i+1)+"번째 작업실적  데이터의 주유량은 필수입력항목 입니다.");
		scwin.breakFlag = "Y";
		if(ds_heavyEquipWorkResults.getRowStatus(i) == "C" && i != 1) {
            ds_heavyEquipWorkResults.removeRow(ds_heavyEquipWorkResults.getTotalRow()-1);
            // ds_heavyEquipWorkResults.undoRow(i);
        }
		return;

	} else {
		scwin.breakFlag = "N";
	}


}

//-------------------------------------------------------------------------
// 저장 f_save
//-------------------------------------------------------------------------
scwin.btn_Save_onClick = async function (e) {

	let row = 0;
	let isSupplyOil     = false; 	/* 주유실적 등록 유무   */
	let isSupplyOilOnly = false;	/* 주유실적만 등록한 경우 */
	ds_oilingResults.removeAll();

	//중기실적 저장
	if (ds_heavyEquipWorkResults.getTotalRow() == 0) return;

	for (i = 0; i < ds_heavyEquipWorkResults.getTotalRow(); i++) {


		let oilPosition = 0;

		if (ds_heavyEquipWorkResults.getModifiedIndex().length == 0 && (ds_oilingResults.getModifiedIndex().length == 0 || (ds_oilingResults.getCellData(i,"oilStatCd") == "" && ds_oilingResults.getRowStatus(i) == "C"))
			&& ds_heavyEquipBasisInformation.getModifiedIndex().length == 0 && ds_heavyEquipNonOperationHour.getModifiedIndex().length == 0) {
	  		$c.win.alert($c.data.getMessage(MSG_CM_ERR_001,"중기실적")); // "@은(는) 변경된 사항이 없습니다."
	  		return;
	  	}

		if (ds_heavyEquipWorkResults.getRowStatus(i) != "R") { /*CUD 작업이 일어난 경우 */ 

			let v_WorkResultsStatus = ds_heavyEquipWorkResults.getRowStatus(i);
			let v_OilStatus	= ds_oilingResults.getRowStatus(i);
			let v_OilRowStatus	= ds_oilingResults.getRowStatus(i);

			if(!scwin.f_validateWrkTime(i)) {
                return false;
            }

			scwin.f_wrkStepChk(i);
			if(scwin.breakFlag == "Y") {
				return;
			}

			ds_heavyEquipWorkResults.setCellData(i, "dptWrkPlCd", ed_works_01.getValue());


			if (ds_heavyEquipWorkResults.getRowStatus(i) == "C") { /* 1 : Insert*/

				for (j=0; j < ds_heavyEquipWorkResults.getTotalRow(); j++) {

					if (ds_heavyEquipWorkResults.getCellData(i,"wrkIndictNo") == ds_heavyEquipWorkResults.getCellData(j,"wrkIndictNo")
					 && ds_heavyEquipWorkResults.getCellData(i,"eqCd") == ds_heavyEquipWorkResults.getCellData(j,"eqCd")
					 && ds_heavyEquipWorkResults.getCellData(i,"impExpClsCd") == ds_heavyEquipWorkResults.getCellData(j,"impExpClsCd")
					 && i != j) {

						$c.win.alert((i+1)+"번째 작업실적  데이터는 중복 데이터이므로 입력하실 수 없습니다.");
					 	gr_heavyEquipWorkResults.setFocusedCell(i, gr_heavyEquipWorkResults.getFocusedColumnIndex());
					 	return;
					}
				}
			} else if (ds_heavyEquipWorkResults.getRowStatus(i) != "D") {/*삭제가 아닌 경우 ==> 2:삭제 */


				if (ds_heavyEquipWorkResults.getRowStatus(i) == "U" ) { // update

					//1. 주유수정이 되었을 때
					if(ds_heavyEquipWorkResults.getCellData(i, "oilStatCd") != ds_heavyEquipWorkResultsOrgin.getCellData(i, "oilStatCd")
						||	ds_heavyEquipWorkResults.getCellData(i, "oilingVol") != ds_heavyEquipWorkResultsOrgin.getCellData(i, "oilingVol")){

						ds_oilingResults.insertRow();
						ds_oilingResults.setCellData(ds_oilingResults.getRowPosition(), "eqCd", ds_heavyEquipWorkResults.getCellData(i, "eqCd"));
						ds_oilingResults.setCellData(ds_oilingResults.getRowPosition(), "wrkDt", ds_heavyEquipWorkResults.getCellData(i, "wrkDt"));
						ds_oilingResults.setCellData(ds_oilingResults.getRowPosition(), "oilStatCd", ds_heavyEquipWorkResults.getCellData(i, "oilStatCd"));
						ds_oilingResults.setCellData(ds_oilingResults.getRowPosition(), "oilStatNm", ds_heavyEquipWorkResults.getCellData(i, "oilStatNm"));
						ds_oilingResults.setCellData(ds_oilingResults.getRowPosition(), "oilingVol", ds_heavyEquipWorkResults.getCellData(i, "oilingVol"));

						ds_heavyEquipWorkResults.setCellData(i, "chk", "T"); //update
						oilPosition = ds_oilingResults.getRowPosition();

						if(ds_heavyEquipWorkResultsOrgin.getCellData(i, "oilingVol") == 0 
								|| (ds_heavyEquipWorkResultsOrgin.getCellData(i, "oilStatCd") == "" || $c.gus.cfIsNull(ds_heavyEquipWorkResultsOrgin.getCellData(i, "oilStatCd")))){

							ds_heavyEquipWorkResults.setCellData(i, "chk", "C"); //insert
						}

					} else {

					}

					if(ds_heavyEquipWorkResults.getCellData(i, "oilStatNm") == "UW"){

						if(ds_oilingResults.getTotalRow() > 0){

							 for(k=0 ; k < ds_oilingResults.getTotalRow() ; k++) {
								 if ((ds_oilingResults.getCellData(k,"eqCd")  == ds_heavyEquipWorkResults.getCellData(i, "eqCd")) 
										 &&(ds_oilingResults.getCellData(k,"wrkDt") == ds_heavyEquipWorkResults.getCellData(i, "wrkDt"))){

									ds_heavyEquipWorkResults.setCellData(i, "oilStatNm", "ALL");
								 } else {

								 }
							 }
						}
					}
				} 

				if(ds_heavyEquipBasisInformation.getCellData(i, "lobranCd") == "6AA" && ds_heavyEquipBasisInformation.getCellData(i, "hveqHomeNm")=="자사"){


				 } else {

				 	// 주유 실적이 있는경우 , 주유소를 선택하지 않거나 , 주유량이 0이면  메시지 처리   후 저장이 안됨. 
				 	if(isSupplyOil &&  ds_oilingResults.getCellData(i,"oilStatCd")  == "" ){

					    	$c.win.alert("주유 실적 등록시  주유소는  필수입력항목 입니다.");
					    	return;

					  	} else if(isSupplyOil &&  ds_oilingResults.getCellData(i,"oilingVol")==0){

					    	$c.win.alert("주유 실적 등록시  주유량은 0보다 커야 합니다.");
					    	return;
					   	}
				 }

				// 자사가 아니면
				if (ds_heavyEquipWorkResults.getCellData(i, "posnClsCd") != 'J') {

					// 용차인 경우 실적 없이 주유 등록만 한 경우  매입거래처 등의 정보 없어도 되지만, 중기 실적 있으면 매입거래처등의 정보 Check 해야 함. 
					     if( !isSupplyOilOnly && ds_heavyEquipWorkResults.getCellData(i,"pchsClntNo") == "") { 
						$c.win.alert((i+1)+"번째 작업실적  데이터의 매입거래처는 필수입력항목 입니다.");
						gr_heavyEquipWorkResults.setFocusedCell(i, gr_heavyEquipWorkResults.getFocusedColumnIndex());
						ed_pchsClntNo.focus();
						return;
					}  

					// 용차인 경우 실적 없이 주유 등록만 한 경우  협력업체는  정보 없어도 되지만, 중기 실적 있으면 협력 업체는 정보 Check 해야 함.  
					if(!isSupplyOilOnly && ds_heavyEquipWorkResults.getCellData(i,"copCoClntNo") == "") {
						$c.win.alert((i+1)+"번째 작업실적  데이터의 협력업체는 필수입력항목 입니다.");
						gr_heavyEquipWorkResults.setFocusedCell(i, gr_heavyEquipWorkResults.getFocusedColumnIndex());
						ed_copCoClntNo.focus();
						return;
					}
				}

				//  실적 없이 주유 등록만 한 경우  매입원가는  정보 없어도 되지만, 중기 실적 있으면 매입원가는  정보 Check 해야 함.  
				if (ds_heavyEquipWorkResults.getCellData(i,"oilStatNm") != "UW"  && ds_heavyEquipWorkResults.getCellData(i,"pchsPcost") == 0) {

					$c.win.alert((i+1)+"번째 작업실적  데이터의 매입원가는 필수입력항목 입니다.");
					ds_heavyEquipWorkResults.setRowPosition(i);
					gr_heavyEquipWorkResults.setFocusedCell(i,"pchsPcost");
					return;
				}
	                  //  실적 없이 주유 등록만 한 경우 조정원가 Check 안하지만, 중기실적이 있는 경우는  조정금액이 있으면 조정사유 있어야 함. 
				if (   !isSupplyOilOnly 
				    && ds_heavyEquipWorkResults.getCellData(i,"ctrlPchsPcost") != 0
				    && ds_heavyEquipWorkResults.getCellData(i,"ctrlPchsPcostRsn") == "") {
					$c.win.alert((i+1)+"번째 작업실적  데이터의 조정사유는 필수입력항목 입니다."); 	
			  		return;
				}
			}

			if (ds_heavyEquipWorkResults.getCellData(i,"cvsslCtrtMgntNo") == "1" && ed_cvsslMgntNo.getValue() == "") {
				$c.win.alert($c.data.getMessage(MSG_CM_ERR_002,"본선계약시 본선관리번호"));
                gr_heavyEquipWorkResults.setFocusedCell(i,"cvsslCtrtMgntNo");
				return; 
			}

			if (ds_heavyEquipWorkResults.getCellData(i,"cvsslCtrtMgntNo") == "1" && ds_heavyEquipWorkResults.getCellData(i,"wrkWt") < "1") {
				$c.win.alert($c.data.getMessage(MSG_CM_ERR_002,"작업톤수"));
                gr_heavyEquipWorkResults.setFocusedCell(i,"wrkWt");
				return;
			}	

		}
		// //필요규격을 입력하지 않을 시 중기규격을 필요규격에 넣어준다.
		if(ds_heavyEquipWorkResults.getCellData(i,"nesEqNrmCd") == "" || $c.gus.cfIsNull(ds_heavyEquipWorkResults.getCellData(i,"nesEqNrmCd"))){
			ds_heavyEquipWorkResults.setCellData(i,"nesEqNrmCd", ds_heavyEquipWorkResults.getCellData(i,"hveqNrmCd"));
		}

        //필요규격을 입력하지 않을 시 중기규격을 필요규격에 넣어준다.
		// if(ds_heavyEquipWorkResults.getCellData(i,"nesEqNrmCd") == "" || $c.gus.cfIsNull(ds_heavyEquipWorkResults.getCellData(i,"nesEqNrmCd"))){
        //     // untouched row가 저장 직전에 U로 바뀌지 않도록 C/U row에만 기본값을 보정한다.
        //     if(ds_heavyEquipWorkResults.getRowStatus(i) != "R"
        //         && ds_heavyEquipWorkResults.getRowStatus(i) != "D"
        //         && (ds_heavyEquipWorkResults.getCellData(i,"nesEqNrmCd") == "" || $c.gus.cfIsNull(ds_heavyEquipWorkResults.getCellData(i,"nesEqNrmCd")))){

        //         ds_heavyEquipWorkResults.setCellData(i,"nesEqNrmCd", ds_heavyEquipWorkResults.getCellData(i,"hveqNrmCd"));
        //     }
        // }

    }

	if (scwin.breakFlag == "Y") return;	

	if (await $c.win.confirm("저장하시겠습니까?")) {
		ds_heavyEquipBasisInformation.setRowPosition(0);


		pos_groupCode = ds_heavyEquipWorkResults.getRowPosition();  // 저장 전의 위치 저장


		ds_heavyEquipBasisInformation.modifyRowStatus(0, "C");

        ds_heavyEquipWorkResults.sort("rowStatus");

        $c.sbm.execute(sbm_save);

	}

};



