//-------------------------------------------------------------------------
// 총투입 시간수
//-------------------------------------------------------------------------
scwin.totInputHhCnt_decode = function(data,data2,rowIdx, colIdx) {
    let row = gr_heavyEquipWorkResults.getFocusedRowIndex();
    let totInputHhCnt = Number(ds_heavyEquipWorkResults.getCellData(rowIdx, "totInputHhCnt"));
    let totInputMintCnt = Number(ds_heavyEquipWorkResults.getCellData(rowIdx, "totInputMintCnt"));
    let realOprtHhCnt = Number(ds_heavyEquipWorkResults.getCellData(rowIdx, "realOprtHhCnt"));
    let realOprtMintCnt = Number(ds_heavyEquipWorkResults.getCellData(rowIdx, "realOprtMintCnt"));

    let result = totInputHhCnt + " " + "H" + "  " + totInputMintCnt + " " + "M"; 
    return result;
}

//-------------------------------------------------------------------------
// 실가동 시간수
//-------------------------------------------------------------------------
scwin.totInputHhCnt_decode2 = function(data,data2,rowIdx, colIdx) {
    let row = gr_heavyEquipWorkResults.getFocusedRowIndex();
    let totInputHhCnt = ds_heavyEquipWorkResults.getCellData(rowIdx, "totInputHhCnt");
    let totInputMintCnt = ds_heavyEquipWorkResults.getCellData(rowIdx, "totInputMintCnt");
    let realOprtHhCnt = ds_heavyEquipWorkResults.getCellData(rowIdx, "realOprtHhCnt");
    let realOprtMintCnt = ds_heavyEquipWorkResults.getCellData(rowIdx, "realOprtMintCnt");


