//-------------------------------------------------------------------------
// 매입원가 데이터셋
//-------------------------------------------------------------------------
scwin.ds_pchsPcost_ondataload = function () {
    let rowCnt = ds_pchsPcost.getTotalRow();

	//원가계산 관련 메세지 처리
	if (rowCnt == 0) {
		$c.win.alert("해당 요율을 조회하는데 실패하였습니다.");
		ds_heavyEquipWorkResults.setCellData(ds_heavyEquipWorkResults.getRowPosition(),"pchsPcost", 0);
		ds_heavyEquipWorkResults.setCellData(ds_heavyEquipWorkResults.getRowPosition(),"upr", 0);

	} else {

		if (ds_pchsPcost.getCellData(0,"uprKnd") == 0) { // 해당 요율이 없습니다. -> 멈춤
			$c.win.alert("해당 요율이 없습니다.");
            ds_heavyEquipWorkResults.setCellData(ds_heavyEquipWorkResults.getRowPosition(),"pchsPcost", 0);
            ds_heavyEquipWorkResults.setCellData(ds_heavyEquipWorkResults.getRowPosition(),"upr", 0);
			return;
		}

		if (ds_pchsPcost.getCellData(0,"uprKnd") == 3 && ds_pchsPcost.getCellData(0,"ctrtEndYn") == 1) { // 계약요율의 계약기간이 만료됨 -> 계속 진행
			$c.win.alert("계약기간이 만료된 계약요율입니다.");

		}

		ds_heavyEquipWorkResults.setCellData(ds_heavyEquipWorkResults.getRowPosition(),"pchsPcost", ds_pchsPcost.getCellData(0, "pchsPcost"));
		ds_heavyEquipWorkResults.setCellData(ds_heavyEquipWorkResults.getRowPosition(),"upr", ds_pchsPcost.getCellData(0, "upr"));

	}

};

//-------------------------------------------------------------------------
// 매입원가 데이터셋
//-------------------------------------------------------------------------
scwin.gr_wrkIndictNoList_onClick = function (rowIndex, columnIndex, columnId) {
	if (rowIndex >= 0){

		if(columnId == "wrkIndictNo" || columnId == "cvsslMgntNo" || columnId == "shiftClsCd" ) {

			if(ds_heavyEquipWorkResults.getTotalRow() > 0 && ds_heavyEquipWorkResults.getModifiedIndex().length > 0){

				//삭제요청 20.06.18
				$c.win.alert('입력된 실적 저장 후 조회하세요'); //저장하시겠습니까
				return;
			} else {



		    dma_condition.set("fromDt", ica_fromDt.getValue());			// 조회시작일자(필수조건 : XXXXXXXX)
		    dma_condition.set("toDt", ica_toDt.getValue());				// 조회종료일자(필수조건 : XXXXXXXX)
		    dma_condition.set("wrkDt", "");						// 작업일자
		    dma_condition.set("lobranCd", acb_lobranCd.getValue());	// 점소코드
		    dma_condition.set("wrkPlCd", ed_works_01.getValue());			// 작업장코드
		    dma_condition.set("cvsslMgntNo", ed_cvsslMgntNo.getValue());		// 본선관리번호
		    dma_condition.set("eqCd", "");						// 
		    dma_condition.set("wrkIndictClsCd", "");						// 작업지시구분명
		    dma_condition.set("wrkIndictNo", ds_wrkIndictNoList.getCellData(ds_wrkIndictNoList.getRowPosition(),"wrkIndictNo"));						// 하역지시번호
		    dma_condition.set("impExpClsCd", ds_wrkIndictNoList.getCellData(ds_wrkIndictNoList.getRowPosition(),"impExpClsCd"));	

		    if(ds_wrkIndictNoList.getCellData(ds_wrkIndictNoList.getRowPosition(), "wrkIndictClsCd") == "C" 
				||ds_wrkIndictNoList.getCellData(ds_wrkIndictNoList.getRowPosition(), "wrkIndictClsCd") == "T" 
					||ds_wrkIndictNoList.getCellData(ds_wrkIndictNoList.getRowPosition(), "wrkIndictClsCd") == "Y"){

                dma_wrkStpCd.set("upperWrkStpCd", "03");
                dma_wrkStpCd.set("lvl", "03");
                dma_wrkStpCd.set("wrkPlanTrgtYn", "1");
                $c.sbm.execute(sbm_wrkStpCd)

			} else {
                dma_wrkStpCd.set("upperWrkStpCd", "01");
                dma_wrkStpCd.set("lvl", "03");
                dma_wrkStpCd.set("wrkPlanTrgtYn", "1");
                $c.sbm.execute(sbm_wrkStpCd)
			}

			$c.sbm.execute(sbm_searchHeavyEquipWorkResults);

			}
            udc_grid2_down.setDisabled(false);
            btn_Save.setDisabled(false)
		}
	}

};


