        // ds_heavyEquipWorkResults.setCellData(ds_heavyEquipWorkResults.getRowPosition(), "drvStaffNm3", "");
        v_drvStaffNo3 = scwin.olddata;
        scwin.f_openCommonPopUp(6,'T', value,'onafteredit');
    } else if (colid == "cvsslCtrtMgntNo") {

        scwin.f_openCommonPopUp(9,'T', value,'onafteredit');
    } else if (colid == "wrkCommCd") {

        ds_heavyEquipWorkResults.setCellData(ds_heavyEquipWorkResults.getRowPosition(), "wrkCommNm", "");
        v_wrkCommCd = scwin.olddata;
        scwin.f_openCommonPopUp(10,'T', value,'onafteredit');

    } else if (colid == "wrkStDt" || colid == "wrkStHh" || colid == "wrkEndDt" || colid == "wrkEndHh") {

        scwin.f_CalcWrkTimeWorkResult(row);

    } else if (colid == "pchsDeptCd") {

        ds_heavyEquipWorkResults.setCellData(ds_heavyEquipWorkResults.getRowPosition(), "pchsDeptNm", "");

        v_pchsDeptCd = scwin.olddata;
        scwin.f_openCommonPopUp(8,'T', value,'onafteredit');
    } else if (colid == "pchsAdptHhCnt" && value == "") {
        ds_heavyEquipWorkResults.setCellData(rowIndex, colid, 0);
    } else if (colid == "wrkWt" && value == "") {
        ds_heavyEquipWorkResults.setCellData(rowIndex, colid, 0.000);
    } else if (colid == "ctrlPchsPcost" && value == "") {
        ds_heavyEquipWorkResults.setCellData(rowIndex, colid, 0);
    } else if (colid == "prtgCost" && value == "") {
        ds_heavyEquipWorkResults.setCellData(rowIndex, colid, 0);
    } else if (colid == "oilingVol" && value == "") {
        ds_heavyEquipWorkResults.setCellData(rowIndex, colid, 0);
    } else if (colid == "tformEqPchsPcost" && value == "") {
        ds_heavyEquipWorkResults.setCellData(rowIndex, colid, 0);
    }

};



