//-------------------------------------------------------------------------
// 그리드 팝업셀 협력업체 콜백
//-------------------------------------------------------------------------
scwin.udc_grid_Popup_callBackFunc2 = function(rtnList) {
    let rowIndex = gr_heavyEquipWorkResults.getFocusedRowIndex();

    // 팝업을 X 버튼으로 닫았을 때
    if (rtnList == null) {
        rtnList = new Array();
        let listLength = 2;
        for (k = 0; k < listLength; k++) {
            rtnList[k] = "";
        }
    }
    // 팝업창 아래의 '닫기' 버튼으로 닫았을 때
    else if (rtnList[0] == "N/A") {
        ds_heavyEquipWorkResults.setCellData(rowIndex, "copCoClntNo", "");
        ds_heavyEquipWorkResults.setCellData(rowIndex, "copCoClntNm", "");
        return;
    }

    if(rtnList != null){
        ds_heavyEquipWorkResults.setCellData(rowIndex, "copCoClntNo", rtnList[0]);
        ds_heavyEquipWorkResults.setCellData(rowIndex, "copCoClntNm", rtnList[1]);
    } else {
        ds_heavyEquipWorkResults.setCellData(rowIndex, "copCoClntNo", "");
        ds_heavyEquipWorkResults.setCellData(rowIndex, "copCoClntNm", "");
    }	

    ds_heavyEquipWorkResults.setCellData(rowIndex, "pchsPcost", "0"); //매입원가

}


