//-------------------------------------------------------------------------
// 작업 지시 번호 그리드 편집시
//-------------------------------------------------------------------------
scwin.gr_wrkIndictNoList_onafteredit = function (rowIndex, columnIndex, value) {

    let colid = gr_wrkIndictNoList.getColumnID(columnIndex);
	var v_mealYn	 = ds_wrkIndictNoList.getCellData(ds_wrkIndictNoList.getRowPosition(), "mealYn");
	var v_pchsDeptCd = ds_wrkIndictNoList.getCellData(ds_wrkIndictNoList.getRowPosition(), "pchsDeptCd");
	var resultRowCnt = ds_heavyEquipWorkResults.getRowCount();
	var wrkIndictNo  = ds_wrkIndictNoList.getCellData(rowIndex,"wrkIndictNo");
	var indictNoIdx  = ds_wrkIndictNoList.getCellData("wrkIndictNo",wrkIndictNo);
	var indictNoResultIdx  = ds_heavyEquipWorkResults.getMatchedIndex("wrkIndictNo", wrkIndictNo, true, 0, resultRowCnt);

	if (colid == "wrkDt" || colid == "wrkStDt" || colid == "wrkStHh" || colid == "wrkEndDt" || colid == "wrkEndHh" || colid == "mealYn"){

		if (ds_wrkIndictNoList.getCellData(rowIndex, colid) != scwin.olddata) {	//인서트일때 왼쪽 데이터가 바뀌면 오른쪽 그리드에도 적용해야한다

			//실적그리드로 불러오기 한 상태에서 작업일자를 수정하면 실적그리드의 컬럼도 변경해주어야 함
			if(resultRowCnt > 0){
				for(i = 0 ; i < resultRowCnt ; i ++) {

					if(ds_wrkIndictNoList.getCellData(ds_wrkIndictNoList.getRowPosition(), "wrkIndictNo")  == ds_heavyEquipWorkResults.getCellData(i,"wrkIndictNo")){
						//같은작업지시번호 행 찾기

						ds_heavyEquipWorkResults.setCellData(i,"wrkDt", ds_wrkIndictNoList.getCellData(ds_wrkIndictNoList.getRowPosition(), "wrkDt"));
						ds_heavyEquipWorkResults.setCellData(i,"wrkStDt", ds_wrkIndictNoList.getCellData(ds_wrkIndictNoList.getRowPosition(), "wrkStDt"));
						ds_heavyEquipWorkResults.setCellData(i,"wrkStHh", ds_wrkIndictNoList.getCellData(ds_wrkIndictNoList.getRowPosition(), "wrkStHh"));
						ds_heavyEquipWorkResults.setCellData(i,"wrkEndDt", ds_wrkIndictNoList.getCellData(ds_wrkIndictNoList.getRowPosition(), "wrkEndDt"));
						ds_heavyEquipWorkResults.setCellData(i,"wrkEndHh", ds_wrkIndictNoList.getCellData(ds_wrkIndictNoList.getRowPosition(), "wrkEndHh"));

						ds_heavyEquipWorkResults.setCellData(i,"totInputHhCnt", ds_wrkIndictNoList.getCellData(ds_wrkIndictNoList.getRowPosition(), "totInputHhCnt"));
						ds_heavyEquipWorkResults.setCellData(i,"totInputMintCnt", ds_wrkIndictNoList.getCellData(ds_wrkIndictNoList.getRowPosition(), "totInputMintCnt"));
						ds_heavyEquipWorkResults.setCellData(i,"realOprtHhCnt", ds_wrkIndictNoList.getCellData(ds_wrkIndictNoList.getRowPosition(), "realOprtHhCnt"));
						ds_heavyEquipWorkResults.setCellData(i,"realOprtMintCnt", ds_wrkIndictNoList.getCellData(ds_wrkIndictNoList.getRowPosition(), "realOprtMintCnt")); 

						if(colid == "mealYn") {

							if(ds_wrkIndictNoList.getCellData(rowIndex, "mealYn") == "1") {
								ds_wrkIndictNoList.setCellData(rowIndex, "mealYn", "0");
							}
						}

						//ds_heavyEquipWorkResults.NameValue(i,"mealYn") 	    = ds_wrkIndictNoList.NameValue(ds_wrkIndictNoList.RowPosition, "mealYn");
					} 
				}
			} else {
				// scwin.f_CalcWrkTime();
			}
			//작업시간 validation
			scwin.f_validateWrkTime(rowIndex);

			//총투입시간, 실가동시간수 계산
			scwin.f_CalcWrkTimeEdit(indictNoIdx);

		}
	}
};


//-------------------------------------------------------------------------
// 공통 Popup 처리 : Gubun Code 에 따른 공통 Popup 을 호출한다.
//-------------------------------------------------------------------------
scwin.f_openCommonPopUp = async function(disGubun, pWinCloseTF, value) {
  	// 선언부
  	var sWinCloseTF = (pWinCloseTF == null) ? "T" : pWinCloseTF;
	var rtnList  = new Array();  // 공통POP-UP -> 요청화면 
	var pSelectID = "";
	var pCode = "";
	var pName = "";
	var pWtitleSearch = "";
	var arrParam = new Array();
	var pLobranCd = "";
	var pLobranNm = "";

	pLobranCd = acb_lobranCd.getValue(); //점소
	pLobranNm = acb_lobranCd.getText(true);

    let evNm = arguments[3] || "";

    if(evNm == "onafteredit" && value == scwin.olddata) {
        return;
    }

    // if(evNm == "ontextimageclick" && value == scwin.olddata) {
    //     return;
    // }

    if (evNm && $c.win.getEventList(gr_heavyEquipWorkResults, evNm)) {
        scwin.eventCnt++;
    }


    $p.setTimeout(function () {
        scwin.eventCnt = 0;
    }, { delay: 1500 });


    if (scwin.eventCnt == 1) {
	switch (disGubun) {
  		case 1:  			
			// 중기 팝업	
				pCode = ds_heavyEquipWorkResults.getCellData(ds_heavyEquipWorkResults.getRowPosition(), "eqShortCd").replace(/\s*$/, '');
				pName = ds_heavyEquipWorkResults.getCellData(ds_heavyEquipWorkResults.getRowPosition(), "vehclNo");
				pDate = ds_heavyEquipWorkResults.getCellData(ds_heavyEquipWorkResults.getRowPosition(), "wrkDt");

                ds_heavyEquipWorkResults.setCellData(ds_heavyEquipWorkResults.getRowPosition(), "eqCd", "");	//중기코드
                ds_heavyEquipWorkResults.setCellData(ds_heavyEquipWorkResults.getRowPosition(), "eqShortCd", "");	//중기단축코드
                ds_heavyEquipWorkResults.setCellData(ds_heavyEquipWorkResults.getRowPosition(), "vehclNo", "");	//중기명	

				arrParam[0] = pLobranCd;			//assgnLobranCd점소코드
				arrParam[1] = ""; 					//eqKndCd중기종류
				arrParam[2] = "";					//clntCd거래처코드
				arrParam[3] = pDate;   				//usblDt작업계획일자
				arrParam[4] = pCode;		  		//eqNo
				arrParam[5] = "";					//eqNm
				arrParam[6] = pWinCloseTF;	//T,F구분
				arrParam[7] = sWinCloseTF;	//T,F구분

                            // 팝업 옵션 설정
                options = {
                    id: "taxPop", 
                    type: "",
                    popupName: "중기조회",
                    width:  1100,                   
                    height: 650
                };

            // 팝업 오픈
                rtnList = await $c.win.openPopup("/ui/ds/op/rscconfirm/transrscconfirm/op_101_01_12p.xml", options, arrParam);      
				/*
					15번째 element가 점소코드를 나타냄.
				*/
				//alert(rtnList.length);
                // $c.win.alert("리턴 타이밍");
                // $c.win.alert("rtnList" + rtnList[2]);

				if(rtnList != null) {
					scwin._lobranCd = rtnList[14];
                }

				if ( rtnList != null && rtnList[0] != "N/A" && rtnList[0] != "undefind" && rtnList.length > 0) {

					ds_heavyEquipWorkResults.setCellData(ds_heavyEquipWorkResults.getRowPosition(), "eqCd",rtnList[12]);	//중기코드
					ds_heavyEquipWorkResults.setCellData(ds_heavyEquipWorkResults.getRowPosition(), "eqShortCd",rtnList[0]);	//중기단축코드
					ds_heavyEquipWorkResults.setCellData(ds_heavyEquipWorkResults.getRowPosition(), "hveqKndCd",rtnList[15]);	//중기종류
					ds_heavyEquipWorkResults.setCellData(ds_heavyEquipWorkResults.getRowPosition(), "hveqKndNm",rtnList[2]);	//중기종류
					ds_heavyEquipWorkResults.setCellData(ds_heavyEquipWorkResults.getRowPosition(), "hveqNrmCd",rtnList[11]);	//중기규격
