        rtnList = new Array();
        var listLength = 2;
        for (var k = 0; k < listLength; k++) {
            rtnList[k] = "";
        }
    }

    // 팝업창 아래의 '닫기' 버튼으로 닫았을 때
    else if (rtnList[0] == "N/A") {
        $c.gus.cfSetValue(ds_heavyEquipWorkResults.setCellData(ds_heavyEquipWorkResults.getRowPosition(), "copCoClntNo"), $c.gus.cfGetHiddenValue(ds_heavyEquipWorkResults.getCellData(ds_heavyEquipWorkResults.getRowPosition(), "copCoClntNo")));
        $c.gus.cfSetValue(ds_heavyEquipWorkResults.setCellData(ds_heavyEquipWorkResults.getRowPosition(), "copCoClntNm"), $c.gus.cfGetHiddenValue(ds_heavyEquipWorkResults.getCellData(ds_heavyEquipWorkResults.getRowPosition(), "copCoClntNm")));
        return;
    }

    if(rtnList != null){
        ds_heavyEquipWorkResults.setCellData(ds_heavyEquipWorkResults.getRowPosition(), "copCoClntNo", rtnList[0]);
        ds_heavyEquipWorkResults.setCellData(ds_heavyEquipWorkResults.getRowPosition(), "copCoClntNm", rtnList[1]);
    } else {
        ds_heavyEquipWorkResults.setCellData(ds_heavyEquipWorkResults.getRowPosition(), "copCoClntNo", "");
        ds_heavyEquipWorkResults.setCellData(ds_heavyEquipWorkResults.getRowPosition(), "copCoClntNm", "");
    }						

    ds_heavyEquipWorkResults.setCellData(ds_heavyEquipWorkResults.getRowPosition(), "pchsPcost", "0"); //매입원가

}

