scwin.gr_heavyEquipWorkResults_ontextimageclick = function (rowIndex, columnIndex) {
    let colid = gr_heavyEquipWorkResults.getColumnID(columnIndex);
    let value = ds_heavyEquipWorkResults.getCellData(rowIndex, colid)

    switch(colid){
        case "eqShortCd":
            scwin.f_openCommonPopUp(1, 'T', value, "ontextimageclick"); break;
        case "pchsClntNo":
            scwin.f_openCommonPopUp(2, 'T', value, "ontextimageclick"); break;
        case "copCoClntNo":
            scwin.f_openCommonPopUp(3, 'T', value, "ontextimageclick"); break;
        case "drvStaffNo1":
            scwin.f_openCommonPopUp(4, 'T', value, "ontextimageclick"); break;
        case "drvStaffNo2":
            scwin.f_openCommonPopUp(5, 'T', value, "ontextimageclick"); break;
        case "drvStaffNo3":
            scwin.f_openCommonPopUp(6, 'T', value, "ontextimageclick"); break;
        case "cvsslCtrtMgntNo":
            scwin.f_openCommonPopUp(12, 'T', value, "ontextimageclick"); break;
        case "wrkCommCd":
            scwin.f_openCommonPopUp(10, 'T', value, "ontextimageclick"); break;
        case "pchsDeptCd":
           scwin.f_openCommonPopUp(8, 'T', value, "ontextimageclick"); break;
    }    


};

