scwin.ds_heavyEquipWorkResults_oncelldatachange = async function (info) {

    // info.oldValue
    // info.newValue
    // info.rowIndex
    // info.colId
    let row = info.rowIndex;
    let colid = info.colID;

    var eqCd  		= ds_heavyEquipWorkResults.getCellData(row, "eqCd");
	var wrkDt 		= ds_heavyEquipWorkResults.getCellData(row, "wrkDt");
	var wrkIndictNo = ds_heavyEquipWorkResults.getCellData(row, "wrkIndictNo");
	var wrkNoIndex  = ds_heavyEquipWorkResults.getMatchedIndex("wrkIndictNo", wrkIndictNo, true, 0, (ds_heavyEquipWorkResults.getRowCount()-1));
	//ds_heavyEquipWorkResults.NameValueRow("wrkIndictNo",wrkIndictNo);
	var pchsAdjmStdCd = ds_heavyEquipWorkResults.getCellData(row, "pchsAdjmStdCd");
	var tocWrkPlYn = ds_heavyEquipWorkResults.getCellData(row, "tocWrkPlYn");

	if(colid == "eqCd"){
        // $c.win.alert("CEll 체인지 타이밍");
        dma_searchHeavyEquipInformation.set("wrkDt", wrkDt);
        dma_searchHeavyEquipInformation.set("eqCd", eqCd);

        ds_heavyEquipBasisInformation.setJSON([]);
		$c.sbm.execute(sbm_searchHeavyEquipInformation)

		if(tocWrkPlYn == "0"){
			ds_heavyEquipWorkResults.setCellData(row, "pchsClntNo", ds_heavyEquipBasisInformation.getCellData(0, "logisHveqRepCopCoNo"));
			ds_heavyEquipWorkResults.setCellData(row, "pchsClntNm", ds_heavyEquipBasisInformation.getCellData(0, "logisHveqRepCopCoNm"));
		} else {
			ds_heavyEquipWorkResults.setCellData(ds_heavyEquipWorkResults.getRowPosition(), "pchsClntNo", ds_tocWrkPl.getCellData(0, "tocClntNo"));
			ds_heavyEquipWorkResults.setCellData(ds_heavyEquipWorkResults.getRowPosition(), "pchsClntNm", ds_tocWrkPl.getCellData(0, "tocClntNm"));
		}

        // scwin.eqCd = rtnList[12];
        // scwin.eqShortCd = rtnList[0];
        // scwin.hveqKndCd = rtnList[15];
        // scwin.hveqNrmCd = rtnList[11];
        // scwin.hveqNrmNm = rtnList[3];

		ds_heavyEquipWorkResults.setCellData(row, "copCoClntNo", ds_heavyEquipBasisInformation.getCellData(0, "clntNo"));
		ds_heavyEquipWorkResults.setCellData(row, "copCoClntNm", ds_heavyEquipBasisInformation.getCellData(0, "clntNm"));
		ds_heavyEquipWorkResults.setCellData(row, "hveqKndCd", ds_heavyEquipBasisInformation.getCellData(0, "hveqKndCd"));

        if(ds_heavyEquipBasisInformation.getCellData(0, "hveqKndNm") == "") {
            ds_heavyEquipWorkResults.setCellData(row, "hveqKndNm", scwin.hveqKndNm);
        } else {
            ds_heavyEquipWorkResults.setCellData(row, "hveqKndNm", ds_heavyEquipBasisInformation.getCellData(0, "hveqKndNm"));
        }

	    ds_heavyEquipWorkResults.setCellData(row, "posnClsCd", ds_heavyEquipBasisInformation.getCellData(0, "posnClsCd"));

	    ds_heavyEquipWorkResults.setCellData(row, "mmLoanYn", ds_heavyEquipBasisInformation.getCellData(0, "mmLoanYn"));

        // dma_nesEqNrmCd.set("param1", ds_heavyEquipWorkResults.getCellData(row, "hveqKndCd"))
        // $c.sbm.execute(sbm_nesEqNrmCd)

	    //Insert일 경우만 발생 
	    if(ds_heavyEquipWorkResults.getCellData(row, "posnClsCd") == "J" 
	    		&& ds_heavyEquipBasisInformation.getCellData(0, "lobranCd") == "6AA" ){

	    	ds_heavyEquipWorkResults.setCellData(row, "oilStatCd", "264756");
	    	ds_heavyEquipWorkResults.setCellData(row, "oilStatNm", "DFT");
	    	oilPusanJ = "Y";
	    }


	} else if (colid == "vsslCtrtYn") {


	} else if((colid == "realOprtHhCnt" || colid == "realOprtMintCnt" ) && pchsAdjmStdCd == "H"){

		 ds_heavyEquipWorkResults.setCellData(row, "pchsPcost", "0");
	} 

	if(ds_heavyEquipWorkResults.getRowStatus(row) == "U"){

		if(colid == "oilStatCd" || colid == "oilingVol" || colid == "oilStatNm" || colid == "chk") {

		} else {

			if (ds_heavyEquipWorkResults.getCellData(row, "oilStatNm") != "ALL" ) {
				ds_heavyEquipWorkResults.setCellData(row, "oilStatNm", "UW");
			}
		}
	}

};

